mapper.select:
select p.id, p.name, p.category_id as categoryId, c.name as categoryName, p.price, p.image, p.description, p.status, min(datediff(ib.expiration_time, now())) as daysToExpire from product p left join category c on c.id = p.category_id left join inventory_batch ib on ib.product_id = p.id
and p.status in (0, 1)
and p.name like concat('%', #{criteria.keyword}, '%')
and p.category_id = #{criteria.categoryId}
and p.status = #{criteria.status}
group by p.id, p.name, p.category_id, c.name, p.price, p.image, p.description, p.status, p.create_time, p.update_time order by ${criteria.sortColumn} ${criteria.sortDirection}, p.id desc limit #{criteria.limit} offset #{criteria.offset}

select p.id, p.name, p.category_id as categoryId, c.name as categoryName, p.price, p.image, p.description, p.status, min(datediff('DAY', now(), ib.expiration_time)) as daysToExpire from product p left join category c on c.id = p.category_id left join inventory_batch ib on ib.product_id = p.id
and p.status in (0, 1)
and p.name like concat('%', #{criteria.keyword}, '%')
and p.category_id = #{criteria.categoryId}
and p.status = #{criteria.status}
group by p.id, p.name, p.category_id, c.name, p.price, p.image, p.description, p.status, p.create_time, p.update_time order by ${criteria.sortColumn} ${criteria.sortDirection}, p.id desc limit #{criteria.limit} offset #{criteria.offset}

select count(1)
from product p

    and p.status in (0, 1)

        and p.name like concat('%', #{criteria.keyword}, '%')


        and p.category_id = #{criteria.categoryId}


        and p.status = #{criteria.status}

select count(1)
from inventory_batch
where product_id = #{productId}

mapper.update:
update product
set status = #{status},
    update_time = now(),
    update_user = #{updateUser}
where id = #{id}

update inventory_batch
set status = 0,
    update_time = now(),
    update_user = #{updateUser}
where product_id = #{productId}
  and status = 1

update product
set status = #{deletedStatus},
    name = concat('deleted-', id, '-', substring(name, 1, 14)),
    update_time = now(),
    update_user = #{updateUser}
where id = #{id}

update category
set status = 0,
    update_time = now(),
    update_user = #{updateUser}
where id = #{id}
  and type = 1
